function parseCSV(text) {
    const lines = text.trim().split('\n');
    const headers = lines[0].split(',').map(h => h.trim());
    return lines.slice(1).map(line => {
        const row = {};
        let currentStr = '';
        let inQuotes = false;
        let colIndex = 0;
        for (let i = 0; i < line.length; i++) {
            const char = line[i];
            if (char === '"') { inQuotes = !inQuotes; } 
            else if (char === ',' && !inQuotes) {
                const header = headers[colIndex];
                if (header) row[header] = currentStr.trim().replace(/^"|"$/g, '');
                currentStr = '';
                colIndex++;
            } else { currentStr += char; }
        }
        const header = headers[colIndex];
        if (header) row[header] = currentStr.trim().replace(/^"|"$/g, '');
        return row;
    }).filter(d => d.Brand && d.Date); // Basic filtering
}

// 1. Process & Clean Data
let bagData = parseCSV(rawMergedData);

// Data Enrichment & Safe Parsing
bagData = bagData.map(d => {
    let dateTimeStr = d.Date;
    if (d.Time) dateTimeStr += ' ' + d.Time;
    
    // Helper to safely parse floats
    const parseNum = (val, def) => {
        const n = parseFloat(val);
        return (isNaN(n) || !isFinite(n)) ? def : n;
    }

    return {
        ...d,
        timestamp: new Date(dateTimeStr),
        // Coordinate Fallbacks
        latitude: parseNum(d.latitude, 0),
        longitude: parseNum(d.longitude, 0),
        // Enriched Fields
        Access_route: d.Access_route ? d.Access_route.trim() : "Offline",
        Weather: d.Weather_at_the_time_of_collection ? d.Weather_at_the_time_of_collection.trim() : "Sunny",
        Motivation: d.Collection_motivation ? d.Collection_motivation.trim() : "Objective",
        // Numerical Attributes mapped to Visuals
        edge_density: parseNum(d.edge_density, 0.05), // Complexity
        colorfulness: parseNum(d.colorfulness, 50),
        pattern_prop: parseNum(d.Main_pattern_proportion, 0.5), // Thickness
        cost: parseNum(d.Obtain_the_cost, 15), // Cost -> Halo/Levitation
        time_cost: parseNum(d.Obtain_the_required_time, 5), // Time -> Line Width
        newness: parseNum(d.Degree_of_newness_and_oldness, 0.9), // Newness -> Opacity
        cleanliness: parseNum(d.Degree_of_cleanliness, 9.0), // Cleanliness -> Roughness/Dash
        // RGB
        r: parseNum(d.r_mean, 128),
        g: parseNum(d.g_mean, 128),
        b: parseNum(d.b_mean, 128)
    };
});

// Sort Chronologically
bagData.sort((a, b) => a.timestamp - b.timestamp);

// --- VIZ 1: THE DRIFTING PATH (Enhanced Map) ---
function initGridMap() {
    const mapContainer = document.getElementById('map-container');
    if(!mapContainer) return;

    // Initialize Map without fixed view, we will fitBounds later
    const map = L.map('map-container');

    L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png', {
        attribution: '&copy; CARTO',
        subdomains: 'abcd',
        maxZoom: 19
    }).addTo(map);

    // Group to hold all features for bounding
    const featureGroup = new L.FeatureGroup();

    // 1. Trajectory Lines (Enhanced with Time Cost)
    const points = [];
    for (let i = 0; i < bagData.length - 1; i++) {
        const curr = bagData[i];
        const next = bagData[i+1];
        
        // Skip invalid coordinates
        if (curr.latitude < 1 || next.latitude < 1) continue;
        
        points.push([curr.latitude, curr.longitude]);

        // Weather Color Logic
        let color = "#ffffff";
        const w = curr.Weather.toLowerCase();
        if (w.includes("sunny")) color = "#ffaa00"; 
        else if (w.includes("rain") || w.includes("cloud")) color = "#00aaff"; 

        // Line Weight based on Time Cost (Harder to get = Thicker line)
        // Normalize time_cost (0-60 mins) to 1-5px
        const weight = 1 + Math.min(curr.time_cost / 10, 4);

        const polyline = L.polyline([[curr.latitude, curr.longitude], [next.latitude, next.longitude]], {
            color: color,
            weight: weight,
            opacity: 0.5,
            smoothFactor: 1
        });
        featureGroup.addLayer(polyline);
    }

    // 2. Nodes (Enhanced with Cost Halo)
    bagData.forEach(d => {
        if(d.latitude < 1) return;

        const isOffline = d.Access_route === "Offline";
        
        // Halo Radius based on Monetary Cost
        // Normalize cost (10-50 RMB) to 4-15px
        const haloRadius = 4 + (d.cost / 5);
        
        // Inner Dot Radius based on Complexity
        const innerRadius = 2 + (d.edge_density * 20);

        // Draw Halo (Cost)
        const halo = L.circleMarker([d.latitude, d.longitude], {
            radius: haloRadius,
            color: "transparent",
            fillColor: d.colorfulness > 80 ? "#ff00ff" : "#00ffff", // High colorfulness = Magenta halo
            fillOpacity: 0.2
        });
        featureGroup.addLayer(halo);

        // Draw Inner Node (Route)
        const node = L.circleMarker([d.latitude, d.longitude], {
            radius: innerRadius,
            color: "#fff",
            weight: 1,
            fillColor: isOffline ? "#fff" : "#000",
            fillOpacity: 1
        }).bindPopup(`
            <div style="color:#333; font-family:sans-serif;">
                <strong>${d.Brand}</strong><br>
                Cost: ¥${d.cost}<br>
                Time: ${d.time_cost} min
            </div>
        `);
        featureGroup.addLayer(node);
    });

    featureGroup.addTo(map);
    
    // [CRITICAL FIX] Auto-zoom to show all points
    if (points.length > 0) {
        map.fitBounds(featureGroup.getBounds(), { padding: [50, 50] });
    } else {
        map.setView([30.25, 120.15], 11); // Fallback
    }
}

// --- VIZ 2: THE LIVING ARCHIVE (Enhanced 3D) ---
function initSpectrum3D() {
    const container = document.getElementById('three-container');
    if(!container) return;
    
    const width = container.clientWidth;
    const height = container.clientHeight;

    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0x050505);
    scene.fog = new THREE.FogExp2(0x050505, 0.002);
    
    // Lighting for Material Texture
    const ambientLight = new THREE.AmbientLight(0xffffff, 0.4);
    scene.add(ambientLight);
    const spotLight = new THREE.SpotLight(0xffffff, 1);
    spotLight.position.set(50, 80, 50);
    spotLight.castShadow = true;
    scene.add(spotLight);

    const camera = new THREE.PerspectiveCamera(50, width / height, 0.1, 1000);
    camera.position.set(0, 50, 80);

    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setSize(width, height);
    renderer.shadowMap.enabled = true;
    container.appendChild(renderer.domElement);

    const controls = new THREE.OrbitControls(camera, renderer.domElement);
    controls.enableDamping = true;
    controls.autoRotate = true;
    controls.autoRotateSpeed = 0.5;

    const group = new THREE.Group();
    const floatingItems = []; // Store for animation

    const gap = 4; 
    const itemsPerRow = Math.ceil(Math.sqrt(bagData.length)); 

    bagData.forEach((d, i) => {
        const color = new THREE.Color(d.r/255, d.g/255, d.b/255);
        const h = Math.max(1, d.colorfulness / 3);
        const thickness = 0.5 + (d.pattern_prop * 2.5); // Thicker if more pattern

        const geometry = new THREE.BoxGeometry(thickness, h, thickness);
        let mesh;

        if (d.Access_route === "Online") {
             const edges = new THREE.EdgesGeometry(geometry);
             const material = new THREE.LineBasicMaterial({ color: color, opacity: 0.5, transparent: true });
             mesh = new THREE.LineSegments(edges, material);
        } else {
            // Material properties based on Cleanliness & Newness
            const opacity = Math.min(1, Math.max(0.3, d.newness)); // Old = Transparent
            const roughness = 1 - (d.cleanliness / 10); // Dirty = Rough

            const material = new THREE.MeshPhysicalMaterial({ 
                color: color, 
                metalness: 0.1,
                roughness: roughness,
                transparent: true,
                opacity: opacity,
                transmission: 1 - opacity // Glassy effect for old bags
            });
            mesh = new THREE.Mesh(geometry, material);
        }

        // Layout
        const row = Math.floor(i / itemsPerRow);
        const col = i % itemsPerRow;
        const x = (col * gap) - (itemsPerRow * gap)/2;
        const z = (row * gap) - (itemsPerRow * gap)/2;
        
        mesh.position.set(x, h/2, z);

        // Store oscillation data based on Cost
        // Higher cost = Faster/Higher float
        const floatSpeed = d.cost / 500; 
        const floatHeight = d.cost / 20; 
        
        floatingItems.push({
            mesh: mesh,
            baseY: h/2,
            speed: 0.02 + floatSpeed,
            amp: 0.5 + floatHeight,
            offset: Math.random() * 10
        });

        // Mood Tilt
        if (d.Collect_feelings_moods === "Excited") {
            mesh.rotation.y = Math.random() * 0.5;
            mesh.rotation.z = Math.random() * 0.2;
        }

        group.add(mesh);
    });

    scene.add(group);
    
    // Floor
    const grid = new THREE.GridHelper(300, 50, 0x333333, 0x111111);
    scene.add(grid);

    // Particle System (Dust/Atmosphere)
    const particlesGeom = new THREE.BufferGeometry();
    const particleCount = 200;
    const posArray = new Float32Array(particleCount * 3);
    for(let i=0; i<particleCount*3; i++) {
        posArray[i] = (Math.random() - 0.5) * 100;
    }
    particlesGeom.setAttribute('position', new THREE.BufferAttribute(posArray, 3));
    const particlesMat = new THREE.PointsMaterial({ size: 0.5, color: 0xffffff, transparent: true, opacity: 0.5 });
    const particlesMesh = new THREE.Points(particlesGeom, particlesMat);
    scene.add(particlesMesh);

    function animate() {
        requestAnimationFrame(animate);
        controls.update();

        // Animate Floating Items
        const time = Date.now() * 0.001;
        floatingItems.forEach(item => {
            item.mesh.position.y = item.baseY + Math.sin(time * item.speed + item.offset) * item.amp;
        });

        // Animate Particles
        particlesMesh.rotation.y += 0.001;

        renderer.render(scene, camera);
    }
    animate();

    window.addEventListener('resize', () => {
        camera.aspect = container.clientWidth / container.clientHeight;
        camera.updateProjectionMatrix();
        renderer.setSize(container.clientWidth, container.clientHeight);
    });
}

// --- VIZ 3: THE BRAND GRAVITY (Enhanced Network) ---
function initFluidIdentity() {
    const container = document.getElementById('d3-network-container');
    if(!container) return;
    container.innerHTML = "";
    const width = container.clientWidth;
    const height = container.clientHeight;

    const svg = d3.select("#d3-network-container").append("svg")
        .attr("width", width).attr("height", height)
        .append("g").attr("transform", `translate(${width/2},${height/2})`);

    const shapeGen = d3.symbol();
    const getShape = (txt) => {
        const t = (txt || "").toLowerCase();
        if(t.includes("memorial")) return d3.symbolCircle;
        if(t.includes("interest")) return d3.symbolStar; // Changed to Star
        if(t.includes("heat")) return d3.symbolTriangle;
        if(t.includes("objective")) return d3.symbolSquare;
        return d3.symbolCross;
    };

    const brands = Array.from(new Set(bagData.map(d => d.Brand)));
    const nodes = [];
    const links = [];

    // Brand Nodes
    brands.forEach(b => nodes.push({ id: b, type: 'brand', r: 0 }));

    bagData.forEach((d, i) => {
        const id = `bag-${i}`;
        nodes.push({
            id: id, type: 'bag', brand: d.Brand,
            color: `rgb(${d.r}, ${d.g}, ${d.b})`,
            motivation: d.Motivation,
            pattern_prop: d.pattern_prop,
            cleanliness: d.cleanliness,
            ageIdx: i, total: bagData.length
        });
        links.push({ source: id, target: d.Brand, val: d });
    });

    // Forces
    const simulation = d3.forceSimulation(nodes)
        .force("link", d3.forceLink(links).id(d => d.id).strength(0.05))
        .force("charge", d3.forceManyBody().strength(d => d.type === 'brand' ? -100 : -5))
        .force("collide", d3.forceCollide().radius(6))
        .force("radial", d3.forceRadial(d => {
            if(d.type === 'brand') return 0;
            return 60 + (d.ageIdx / d.total) * 250;
        }, 0, 0).strength(0.8));

    // Brand Orbit Circles (Background)
    const orbitGroup = svg.append("g").attr("class", "orbits");
    brands.forEach((b, i) => {
        // Just visual decoration implies gravity zones
        orbitGroup.append("circle")
            .attr("r", 30 + (i % 3) * 20)
            .attr("fill", "none")
            .attr("stroke", "#222")
            .attr("stroke-dasharray", "2,4");
    });

    // Render Links
    const link = svg.append("g").selectAll("line")
        .data(links).enter().append("line")
        .attr("stroke", "#555")
        // Width based on Pattern Proportion (Louder visual = Thicker link)
        .attr("stroke-width", d => 0.5 + (d.val.pattern_prop * 2)) 
        // Dash based on Cleanliness (Dirty = Dashed)
        .attr("stroke-dasharray", d => d.val.cleanliness < 8 ? "2,2" : "none") 
        .attr("opacity", 0.4);

    // Render Bag Nodes
    const nodeBag = svg.append("g").selectAll("path")
        .data(nodes.filter(n => n.type === 'bag')).enter().append("path")
        .attr("d", d => shapeGen.type(getShape(d.motivation)).size(60)())
        .attr("fill", d => d.color)
        .attr("stroke", "#000").attr("stroke-width", 0.5)
        .on("mouseover", function() { d3.select(this).attr("stroke", "#fff").attr("stroke-width", 2); })
        .on("mouseout", function() { d3.select(this).attr("stroke", "#000").attr("stroke-width", 0.5); });

    // Render Brand Text
    const nodeBrand = svg.append("g").selectAll("text")
        .data(nodes.filter(n => n.type === 'brand')).enter().append("text")
        .text(d => d.id).attr("text-anchor", "middle").attr("dy", ".3em")
        .attr("fill", "#fff").attr("font-size", "11px").attr("font-weight", "bold")
        .style("text-shadow", "0 0 4px #000");

    simulation.on("tick", () => {
        link.attr("x1", d => d.source.x).attr("y1", d => d.source.y)
            .attr("x2", d => d.target.x).attr("y2", d => d.target.y);
        nodeBag.attr("transform", d => `translate(${d.x},${d.y})`);
        nodeBrand.attr("x", d => d.x).attr("y", d => d.y);
    });
}

// Start
document.addEventListener('DOMContentLoaded', () => {
    initGridMap();
    initSpectrum3D();
    initFluidIdentity();
});